// ---------------------------------------------------------------------------
// Story 1 — TokenSet
// ---------------------------------------------------------------------------
export const TokenSet = {
  name: 'Token set',
  render: () => {
    const durationRows = FLUENT_DURATIONS.map(d => `
      <tr ${d.outlier ? 'style="background:#fffdf0;"' : ''}>
        <td class="mono" ${d.outlier ? 'style="font-weight:700;color:#856404;"' : ''}>${d.name}
          ${d.outlier ? '<span class="outlier-badge">character outlier</span>' : ''}
        </td>
        <td class="mono">${d.value}ms</td>
        <td><div style="height:6px;background:#0078d4;border-radius:3px;width:${Math.round(d.value / 5)}px;opacity:0.7;"></div></td>
        <td style="font-size:12px;color:#555;">${d.desc}</td>
      </tr>
    `).join('');

    const easingRows = FLUENT_EASINGS.map(e => {
      const dc = dirColors[e.direction] || '#333';
      return `
        <tr>
          <td class="mono">${e.name}</td>
          <td class="mono">${cb(e.curve)}</td>
          <td>${easingSVG(e.curve)}</td>
          <td><span style="font-size:10px;font-weight:700;padding:1px 6px;border-radius:3px;
            background:${dc}22;color:${dc};">${e.direction}</span></td>
          <td style="font-size:11px;color:#888;">${e.intensity}</td>
        </tr>
      `;
    }).join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>${baseStyles}</style>
      <div class="page">
        <div class="sys-badge">Fluent 2</div>
        <div class="page-title">Token set</div>
        <div class="page-desc">
          Fluent 2 uses superlative naming for durations (UltraFast → UltraSlow) plus
          <code style="font-family:monospace;background:#eee;padding:1px 4px;border-radius:3px;">durationGentle</code>
          — a character word that breaks the pure speed logic of the scale.
          9 easing curves organized as direction × intensity (Max/Mid/Min).
        </div>
        <div class="section-label">Duration scale (8 tokens)</div>
        <table>
          <thead><tr><th>Token</th><th>Value</th><th>Scale</th><th>Description</th></tr></thead>
          <tbody>${durationRows}</tbody>
        </table>
        <div class="section-label">Easing curves (9 tokens)</div>
        <table>
          <thead><tr><th>Token</th><th>Cubic-bezier</th><th>Preview</th><th>Direction</th><th>Intensity</th></tr></thead>
          <tbody>${easingRows}</tbody>
        </table>
        <div style="background:#e8f4ff;border-radius:6px;padding:14px 16px;font-size:13px;color:#333;line-height:1.6;">
          <strong>durationGentle insight:</strong> The token breaks the pure speed logic of the rest of the scale.
          "Gentle" is a character word — it signals a specific use (a soft, unhurried transition) that speed alone cannot capture.
          It is a tactile outlier in a system otherwise organized by speed superlatives.
        </div>
      </div>
    `;
    return el;
  },
};

// ---------------------------------------------------------------------------
// Story 2 — AnimatedDemo
// ---------------------------------------------------------------------------
export const AnimatedDemo = {
  name: 'Animated demo',
  render: () => {
    const durationOptions = FLUENT_DURATIONS.map(d =>
      `<option value="${d.value}">${d.name} (${d.value}ms)</option>`
    ).join('');

    const easingOptions = FLUENT_EASINGS.map(e =>
      `<option value="${cb(e.curve)}">${e.name}</option>`
    ).join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${baseStyles}
        .controls { display: flex; gap: 12px; align-items: center; flex-wrap: wrap; margin-bottom: 32px; }
        select { padding: 7px 10px; border: 1px solid #e0e0e0; border-radius: 4px;
          font-family: inherit; font-size: 12px; background: #fff; min-width: 220px; }
        .play-btn { padding: 8px 20px; background: #0078d4; color: #fff; border: none;
          border-radius: 4px; font-size: 13px; font-weight: 600; cursor: pointer; font-family: inherit; }
        .play-btn:disabled { opacity: 0.5; cursor: default; }
        .stage { width: 280px; height: 80px; background: #cce4f6; border-radius: 6px;
          position: relative; margin-bottom: 16px; }
        .ref-box { width: 60px; height: 60px; background: #0078d4; border-radius: 4px;
          position: absolute; left: 0; top: 10px; }
        .labels { font-size: 11px; font-family: monospace; color: #555; line-height: 1.8; }
      </style>
      <div class="page">
        <div class="sys-badge">Fluent 2</div>
        <div class="page-title">Animated demo</div>
        <div class="page-desc">Select a duration and easing, then click Play.</div>
        <div class="controls">
          <select id="durSel">${durationOptions}</select>
          <select id="easSel">${easingOptions}</select>
          <button class="play-btn" id="playBtn">Play</button>
        </div>
        <div class="stage"><div class="ref-box" id="box"></div></div>
        <div class="labels" id="labels"></div>
      </div>
    `;

    const durSel = el.querySelector('#durSel');
    const easSel = el.querySelector('#easSel');
    const playBtn = el.querySelector('#playBtn');
    const box = el.querySelector('#box');
    const labels = el.querySelector('#labels');

    function updateLabels() {
      labels.textContent = `duration: ${durSel.value}ms   easing: ${easSel.value}`;
    }
    updateLabels();
    durSel.addEventListener('change', updateLabels);
    easSel.addEventListener('change', updateLabels);

    playBtn.addEventListener('click', () => {
      if (playBtn.disabled) return;
      playBtn.disabled = true;
      const dur = parseInt(durSel.value, 10);
      box.animate(
        [{ transform: 'translateX(0px)' }, { transform: 'translateX(120px)' }, { transform: 'translateX(0px)' }],
        { duration: dur * 2, easing: easSel.value, fill: 'forwards' }
      ).onfinish = () => { playBtn.disabled = false; };
    });

    return el;
  },
};

